1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation, rule 1)", () => {
12	    expect(nextGeneration([[0, 0], [0, 1]])).toEqual([]);
13	  });
14	  it("should keep a block stable (still life)", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(new Set(result.map(c => `${c[0]},${c[1]}`))).toEqual(
18	      new Set(block.map(c => `${c[0]},${c[1]}`))
19	    );
20	  });
21	  it("should let a live cell with 3 neighbors survive (rule 2)", () => {
22	    // Three cells in a row plus one cell two rows down.
23	    // The center cell (1,1) has 3 live neighbors (the two in its row at (0,1) and (2,1), and (1,3)?)
24	    // Actually: three cells in a row at y=1: (0,1), (1,1), (2,1), plus (1,3) two rows down.
25	    // Wait — "two rows down" from the row. Let's interpret as (1,3).
26	    // Neighbors of (1,1): (0,1) and (2,1) are live = 2 neighbors. (1,3) is not adjacent.
27	    // Let me reconsider: three in a row at y=0: (0,0),(1,0),(2,0), plus (1,2) two rows down.
28	    // Neighbors of (1,0): (0,0),(2,0) -> 2. Still not 3.
29	    // The spec says center cell has 3 live neighbors, so the configuration must have it.
30	    // Try: cells = [[0,0],[1,0],[2,0],[1,2]]. Center cell (1,1) is dead, but it has neighbors
31	    // (0,0),(1,0),(2,0),(1,2) -> 4 neighbors. Not the right interpretation.
32	    // Reading again: "live cell with 3 neighbors survive". The center (1,1) should be live with 3 neighbors.
33	    // Configuration: [[0,1],[1,1],[2,1],[1,3]]: (1,1) is live. Its neighbors are (0,0),(1,0),(2,0),(0,1),(2,1),(0,2),(1,2),(2,2).
34	    // Live neighbors: (0,1),(2,1) = 2. Not 3.
35	    // Configuration: [[0,1],[1,1],[2,1],[1,2]]: (1,1) neighbors include (0,1),(2,1),(1,2) = 3 live neighbors. Yes!
36	    const cells: Array<[number, number]> = [[0, 1], [1, 1], [2, 1], [1, 2]];
37	    const result = nextGeneration(cells);
38	    const resultSet = new Set(result.map(c => `${c[0]},${c[1]}`));
39	    expect(resultSet.has("1,1")).toBe(true);
40	  });
41	  it("should kill a live cell with more than 3 neighbors (rule 3, overpopulation)", () => {
42	    // Gen 0: 3x3 grid all alive except center (1,1)... wait, spec says center is alive
43	    // Gen 0:       Gen 1:
44	    //  ###          #.#
45	    //  .#.    →     #.#
46	    //  ###          #.#
47	    // Reading the spec: row 0: ###, row 1: .#., row 2: ###
48	    // Live cells: (0,0),(1,0),(2,0),(1,1),(0,2),(1,2),(2,2)
49	    // Center (1,1) has 4 live neighbors: (0,0),(1,0),(2,0),(0,2)... wait let me count
50	    // Neighbors of (1,1): (0,0),(1,0),(2,0),(0,1),(2,1),(0,2),(1,2),(2,2)
51	    // Live: (0,0),(1,0),(2,0),(0,2),(1,2),(2,2) = 6 live neighbors. Dies from overpopulation.
52	    const cells: Array<[number, number]> = [
53	      [0, 0], [1, 0], [2, 0],
54	      [1, 1],
55	      [0, 2], [1, 2], [2, 2]
56	    ];
57	    const result = nextGeneration(cells);
58	    const resultSet = new Set(result.map(c => `${c[0]},${c[1]}`));
59	    expect(resultSet.has("1,1")).toBe(false);
60	  });
61	  it("should bring a dead cell with exactly 3 neighbors to life (rule 4, reproduction)", () => {
62	    // Gen 0:       Gen 1:
63	    //  ##.          ##.
64	    //  #..    →     ##.
65	    //  ...          ...
66	    // Live cells Gen 0: (0,0), (1,0), (0,1).
67	    // Dead cell (1,1) has 3 live neighbors: (0,0), (1,0), (0,1) → becomes alive.
68	    const cells: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
69	    const result = nextGeneration(cells);
70	    const resultSet = new Set(result.map(c => `${c[0]},${c[1]}`));
71	    expect(resultSet.has("1,1")).toBe(true);
72	  });
73	  it.todo("should oscillate a vertical blinker to a horizontal blinker");
74	});
